import React, { useState, useEffect } from 'react';
import api from '/api.jsx'; // 

function Marquee() {
  const [streamTitle, setStreamTitle] = useState('Loading...');

  const fetchStreamTitle = async () => {
    try {
      // Bypass cache by adding a unique timestamp parameter
      const response = await api.get('/', { params: { t: Date.now() } });

      // Check the response structure
      if (response.data && response.data.now_playing && response.data.now_playing.song) {
        const title = response.data.now_playing.song.title;
        setStreamTitle(title);
      } else {
        console.warn('Unexpected response structure:', response.data);
        setStreamTitle('Failed to fetch title'); 
      }
    } catch (error) {
      console.error('Error fetching stream title:', error);
      setStreamTitle('Failed to fetch title'); // Inform user of the error
    }
  };

  useEffect(() => {
    const refreshInterval = setInterval(fetchStreamTitle, 15000); // Refresh every 15 seconds

    // Fetch the stream title initially
    fetchStreamTitle();

    return () => {
      clearInterval(refreshInterval); // Clear the interval when the component unmounts
    };
  }, []);

  return (
    <div className="marquee">
        <div className="flashing-dot"></div>
        <span>{streamTitle}</span>
    </div>
  );
}

export default Marquee;
